var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"FATHER_NPC_NANAHARA_PILOT","text":{"KOREA":"작전 준비가 끝났습니다, 당주님.","JPN":"ご当主、作戦準備が整いました。","ENG":"We’re ready to launch the plan, Lady Nanahara.","TWN":"堂主，作戰準備就緒。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"FATHER_NPC_NANAHARA_PILOT","text":{"KOREA":"이 계획만 성공하면 오로치는 봉인과 함께 영원히 현실세계에서 격리되겠죠.","JPN":"この計画さえ成功すれば、オロチは封印され、現実世界から永遠に隔離されるでしょう。","ENG":"If we succeed, Orochi will be separated from the Normalside forever.","TWN":"只要這次計劃成功，大蛇就會和封印一起永遠被隔離在現實世界之外。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"FATHER_NPC_NANAHARA_PILOT","text":{"KOREA":"보이시나요? 오랫동안 뿔뿔이 흩어졌던 연합이, 당주님의 뜻에 따라 다시 하나로 뭉쳤습니다.","JPN":"見えますか？　長い間分裂していた連合が、七原家当主の意思によって再び団結しました。","ENG":"Do you see this? All the families who left the Alliance have gathered here to help you.","TWN":"堂主有看到嗎？長久以來如一盤散沙的聯盟，現在照著堂主的意思又再次團結起來。"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FATHER_NPC_NANAHARA_PILOT","text":{"KOREA":"모두가 당주님을 믿고 평화를 위해 싸우기로 결심한 겁니다.","JPN":"皆がご当主様を信じて、平和のために戦うことを決意したのです。","ENG":"They are ready to fight for everlasting peace, believing in you.","TWN":"所有人都下定決心要相信堂主，並且為和平而戰。"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……고마워요, 카토리 당주.","JPN":"……ありがとうございます、香取家当主。","ENG":"Thank you, Mr. Katori.","TWN":"……謝謝你，香取堂主。"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"모두들. 이렇게 한 자리에 모여주어 고맙습니다.","JPN":"皆様、お集まりいただきありがとうございます。","ENG":"I thank you all for coming.","TWN":"首先，謝謝大家齊聚在這裡。"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"선조 때부터 이어져 온 이 오랜 의무도, 이젠 매듭을 지을 때가 왔어요.","JPN":"先祖代々伝えられてきた義務をようやく果たす時が来ました。","ENG":"The duty that has been handed down to us through generations will be finally over.","TWN":"長久以來從祖先傳承至今的義務，現在終於要畫下句點。"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"오로치는 봉인과 함께, 나락으로 떨어질 것입니다.","JPN":"オロチは封印と共に、奈落に落ちるでしょう。","ENG":"We will send Orochi to the netherworld forever, along with its seal.","TWN":"大蛇將和封印一起落入地獄。"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그러니 여러분은 저를 믿고 따라주세요.","JPN":"皆様、どうか私を信じて付いてきてください。","ENG":"So everyone, please follow my command.","TWN":"請大家相信並且跟隨我。"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>모두가 널 믿었지.</color>","JPN":"<color=#ff3636>皆がお前を信じた。</color>","ENG":"<color=#ff3636>Everyone trusted you.</color>","TWN":"<color=#ff3636>大家當然相信你。</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>아니, 그들은 너의 어리석은 예언을 믿었을 뿐이야.</color>","JPN":"<color=#ff3636>いや、彼らは愚かなお前の予言を信じただけだ。</color>","ENG":"<color=#ff3636>No, they trusted your stupid prophecy.</color>","TWN":"<color=#ff3636>不對，他們信的是你愚蠢預言。</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>그리고, 결말은 처참했지.</color>","JPN":"<color=#ff3636>そして、結末は凄惨だった。</color>","ENG":"<color=#ff3636>And in the end, it was horror.</color>","TWN":"<color=#ff3636>然而，結局很悽慘。</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"저, 저 좀 살려주십시오! 당주님!","JPN":"た、助けてください！　ご当主！","ENG":"H-help me, Lady Nanahara!","TWN":" 堂主！救…救命！"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"이럴 수는 없어. 하필이면 지금 독기가 쏟아져나온다고? 이건 예견과 다르잖아!","JPN":"ありえない。どうして今になって毒が溢れだすんだ？　予言と違うじゃないか！","ENG":"How can it be? Poison pouring out at this time? It’s different from the prophecy!","TWN":"怎麼會這樣？毒氣怎麼會偏偏現在洩出來？這跟預言不一樣啊！"},"stage":{"bg":"REEDS_FIELD","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>말라 바스러지는 갈대처럼.</color>","JPN":"<color=#ff3636>まるで枯れ朽ちていく葦の如く。</color>","ENG":"<color=#ff3636>Like withering weeds.</color>","TWN":"<color=#ff3636>像乾枯的蘆葦一樣。</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>너를 믿었던 가련한 이들은 네 눈앞에서 시들고 말았지.</color>","JPN":"<color=#ff3636>お前を信じた可哀そうな人間どもは、お前の目の前で散っていった。</color>","ENG":"<color=#ff3636>Those who trusted you withered away, right in front of you.</color>","TWN":"<color=#ff3636>那些相信你的可憐人，在你眼前枯萎。</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};